INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ecisão de resolução do presente contrato por meio de uma declaração inequívoca (por exemplo, carta enviada pelo correio ou correio eletrónico). Pode utilizar o modelo de formulário de resolução, mas tal não é obrigatório. (3)
