INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ara efeitos do disposto no artigo 2.º do presente decreto-lei, e sem prejuízo do disposto na Lei n.º 68/2019, de 27 de agosto, na sua redação atual, o Ministério Público dispõe dos poderes de investigação e de aplicação previstos nas alíneas a) e d) do n.º 3 e nas alíneas a), b), c), e) e f) do n.º 4 do artigo 9.º, cujo exercício obedece ao disposto no artigo 10.º, ambos do Regulamento (UE) 2017/2394.            
         
   
     
                         
                          
